<main class="container"><section class="section"><h1 class="page-title"><?php echo htmlspecialchars($event['titulo'], ENT_QUOTES, 'UTF-8'); ?></h1><p><span class="badge badge-<?php echo htmlspecialchars($event['estado'], ENT_QUOTES, 'UTF-8'); ?>"><?php echo htmlspecialchars($event['estado'], ENT_QUOTES, 'UTF-8'); ?></span></p><?php if (!empty($event['imagen'])): ?><img class="service-img" src="/GoldenHoursEvents/<?php echo htmlspecialchars($event['imagen'], ENT_QUOTES, 'UTF-8'); ?>" alt=""><?php endif; ?><p><?php echo nl2br(htmlspecialchars($event['descripcion'], ENT_QUOTES, 'UTF-8')); ?></p><p><strong>Categoría:</strong> <?php echo htmlspecialchars($event['categoria'] ?? '-', ENT_QUOTES, 'UTF-8'); ?></p><p><strong>Inicio:</strong> <?php echo htmlspecialchars($event['fecha_inicio'], ENT_QUOTES, 'UTF-8'); ?></p><p><strong>Final:</strong> <?php echo htmlspecialchars($event['fecha_fin'] ?? '-', ENT_QUOTES, 'UTF-8'); ?></p><p><strong>Lugar:</strong> <?php echo htmlspecialchars($event['lugar'], ENT_QUOTES, 'UTF-8'); ?> — <?php echo htmlspecialchars($event['direccion'] ?? '', ENT_QUOTES, 'UTF-8'); ?></p><p><strong>Cupo:</strong> <?php echo (int) $event['cupo_total']; ?></p><p><strong>Precio:</strong> S/ <?php echo number_format((float) $event['precio'], 2); ?></p><?php if (!empty($event['motivo_rechazo'])): ?><p class="alert alert-error"><strong>Motivo:</strong> <?php echo htmlspecialchars($event['motivo_rechazo'], ENT_QUOTES, 'UTF-8'); ?></p><?php endif; ?><a class="btn btn-outline" href="/GoldenHoursEvents/views/organizer/my_events.php">Volver</a></section></main><?php require_once __DIR__ . '/../../includes/footer.php'; ?>
